-- Drop tabelle esistenti (se presenti)
DROP TABLE IF EXISTS logs CASCADE;
DROP TABLE IF EXISTS users CASCADE;

-- Sequenze per le chiavi primarie
DROP SEQUENCE IF EXISTS users_id_seq CASCADE;
DROP SEQUENCE IF EXISTS logs_id_seq CASCADE;
CREATE SEQUENCE users_id_seq START 1;
CREATE SEQUENCE logs_id_seq START 1;

-- Tabella: users
CREATE TABLE users (
    id          INTEGER PRIMARY KEY DEFAULT nextval('users_id_seq'),
    nome_cognome TEXT,
    pin          TEXT UNIQUE,
    device_token TEXT UNIQUE,
    device_user_agent TEXT,
    is_active    BOOLEAN DEFAULT TRUE,
    is_admin     BOOLEAN DEFAULT FALSE
);

-- Tabella: logs
CREATE TABLE logs (
    id              INTEGER PRIMARY KEY DEFAULT nextval('logs_id_seq'),
    user_id         INTEGER,
    timestamp       TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    tipo_timbratura TEXT,
    CONSTRAINT fk_logs_user FOREIGN KEY (user_id) REFERENCES users (id)
);

