-- Aggiorna le sequenze ai valori corretti dopo l'import
SELECT setval('users_id_seq', COALESCE((SELECT MAX(id) FROM users), 1));
SELECT setval('logs_id_seq',  COALESCE((SELECT MAX(id) FROM logs),  1));

